function captureActiveTokens(tokens: string[]): string[] {
  return tokens
    .filter(t => t.length > 10)
    .map(t => t.trim());
}

examples.toCode:
fun captureActiveTokens(tokens: List<String>): List<String> {
    return tokens
        .filter { it.length > 10 }
        .map { it.trim() }
}
